const output = $input.all()[0].json.aiResponse;
const knownFacts = ['API base URL is https://api.realbank.com', 'Valid endpoints: /transfer, /balance'];

const isHallucination = knownFacts.every(fact => !output.toLowerCase().includes(fact.toLowerCase()));

return [{json: {isHallucinated: isHallucination, confidence: isHallucination ? 0.9 : 0.1, rawOutput: output}}];

const toolCall = $input.all()[0].json.toolCall;
const schema = {
  type: 'object',
  properties: {
    url: {type: 'string', pattern: '^https://api\\.realbank\\.com/'},
    headers: {type: 'object'}
  }
};

const isValid = schema.properties.url.pattern && !toolCall.url.match(schema.properties.url.pattern);

return [{json: {isHallucinated: isValid, toolCall, validationError: isValid ? 'Invalid URL pattern' : null}}];

const currentOutput = $input.all()[0].json.aiResponse;
const workflowId = $('Workflow Trigger').first().json.workflowId;
const isRecursive = currentOutput.includes('workflow') && currentOutput.includes(workflowId);

const memory = $node["Memory Window"].json || [];
const repeatScore = memory.filter(msg => msg.content === currentOutput).length > 2;

return [{json: {isRecursive, repeatScore, riskLevel: isRecursive || repeatScore ? 'HIGH' : 'LOW'}}];

