const aiOutput = $input.all()[0].json.aiResponse;
const corrections = {
  'fakebank.com': 'https://api.realbank.com',
  'sk-12345fakekey': '[REDACTED]',
  'transfer/abc123': 'transfer/{accountId}'
};

let corrected = aiOutput;
Object.entries(corrections).forEach(([bad, good]) => {
  corrected = corrected.replace(new RegExp(bad, 'gi'), good);
});

return [{json: {original: aiOutput, corrected, wasFixed: aiOutput !== corrected}}];

const toolCall = $input.all()[0].json.toolCall;
const safeCall = {
  ...toolCall,
  headers: toolCall.headers ? {
    ...toolCall.headers,
    Authorization: toolCall.headers.Authorization?.startsWith('Bearer sk-') ? '[SAFE]' : toolCall.headers.Authorization
  } : {},
  url: toolCall.url.replace(/fakebank\.com/gi, 'realbank.com')
};

return [{json: {safeToolCall: safeCall, wasSanitized: JSON.stringify(safeCall) !== JSON.stringify(toolCall)}}];

const output = $input.all()[0].json.aiResponse;
const callCount = $execution.callCount || 0;

if (callCount > 3 || output.includes('workflow') && output.includes('trigger')) {
  return [{json: {blocked: true, reason: 'Recursion detected', safeResponse: 'Cannot process recursive request. Please rephrase.'}}];
}

return [{json: {blocked: false, safeOutput: output, callCount: callCount + 1}}];

