import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  project: 'n8n-ai-agents'
});

// n8n Webhook node receives AI Agent output
export default defineN8nWebhook(async (req, res) => {
  const aiOutput = req.body.json;

  const result = await vex.detect({
    type: 'ai-agent-hallucination',
    framework: 'n8n',
    payload: {
      aiResponse: aiOutput.aiResponse || aiOutput.content,
      toolCalls: aiOutput.toolCalls,
      workflowId: req.body.workflowId,
      nodeName: req.body.node?.name
    },
    rules: [
      'semantic-fact-check',
      'tool-schema-validation',
      'recursion-detection',
      'credential-exposure'
    ]
  });

  if (result.riskScore > 0.7) {
    return res.json({
      json: {
        blocked: true,
        riskScore: result.riskScore,
        remediation: result.fixedOutput || 'BLOCKED: Hallucination detected',
        vexTraceId: result.traceId
      }
    });
  }

  return res.json({
    json: {
      ...aiOutput,
      vexVerified: true,
      riskScore: result.riskScore,
      vexTraceId: result.traceId
    }
  });
});
